script.inlineScript:
import { readFileSync, writeFileSync } from 'fs';

const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
const projectName = input.steps?.['enter-data']?.projectName || 'untitled';
const description = input.steps?.['enter-data']?.description || '';

const slug = projectName.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');

writeFileSync('/output/result.json', JSON.stringify({
  slug,
  projectName,
  description,
  summary: `Project "${projectName}" (${slug}) created successfully.`
}));
